<?php include 'app/views/layouts/header.php'; ?><h2 class='fw-bold'>➕ Add Project</h2><p class='text-muted'>Project data entry based on Extension Office requirements.</p><?php if($message): ?><div class='alert alert-info'><?= $message ?></div><?php endif; ?><div class='card p-4'><form method='POST'><div class='row g-3'><div class='col-md-4'><label>Program</label><select name='program_id' class='form-select' required><?php foreach($programs as $p): ?><option value='<?= $p['id'] ?>'><?= htmlspecialchars($p['program_title']) ?></option><?php endforeach; ?></select></div><div class='col-md-8'><label>Project Title</label><input name='project_title' class='form-control' required></div><div class='col-md-4'><label>SDG</label><input name='sdg' class='form-control'></div><div class='col-md-4'><label>Partners</label><input name='partners' class='form-control'></div><div class='col-md-4'><label>Type of Clientele</label><input name='type_of_clientele' class='form-control'></div><div class='col-md-4'><label>Leader</label><input name='leader' class='form-control'></div><div class='col-md-4'><label>Assistant Leader</label><input name='assistant_leader' class='form-control'></div><div class='col-md-4'><label>Members</label><textarea name='members' class='form-control'></textarea></div><div class='col-md-3'><label>Participants</label><input type='number' name='participants' class='form-control' value='0'></div><div class='col-md-3'><label>Project Cost</label><input type='number' step='0.01' name='project_cost' class='form-control'></div><div class='col-md-3'><label>Start Date</label><input type='date' name='start_date' class='form-control'></div><div class='col-md-3'><label>End Date</label><input type='date' name='end_date' class='form-control'></div><div class='col-md-4'><label>Special Order No.</label><input name='special_order_no' class='form-control'></div><div class='col-md-4'><label>Municipality</label><input name='municipality' class='form-control'></div><div class='col-md-4'